 1	import React, { FC, memo } from 'react';
 2	import classNames from 'classnames';
 3	
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { Label, Popover, PopoverPosition } from '@patternfly/react-core';
 6	
 7	import '../MigrationPolicySelectorLabel.scss';
 8	
 9	type MigrationPolicySelectorProps = {
10	  isVMILabel?: boolean;
11	  matchKey: string;
12	  value: string;
13	};
14	
15	export const MigrationPolicySelector: FC<MigrationPolicySelectorProps> = memo(
16	  ({ isVMILabel, matchKey, value }) => {
17	    const { t } = useKubevirtTranslation();
18	    const labelBodyContent = `${matchKey}: ${value}`;
19	    return (
20	      <Popover
21	        aria-label="Match label selector"
22	        bodyContent={`${matchKey}: ${value}`}
23	        headerContent={t('Match label')}
24	        position={PopoverPosition.top}
25	      >
26	        <Label
27	          onClick={(e) => {
28	            e.preventDefault();
29	          }}
30	          color={isVMILabel ? 'grey' : 'blue'}
31	        >
32	          <div className={classNames({ 'kv-migration-policy__label-vm': isVMILabel })}>
33	            {labelBodyContent}
34	          </div>
35	        </Label>
36	      </Popover>
37	    );
38	  },
39	);

